# Fast demo runner for project\n# This script starts the backend and serves the frontend in production‑mode for instant load times.\n\n# Resolve project root\n$PROJECT_ROOT = $PSScriptRoot\nif (-not $PROJECT_ROOT) { $PROJECT_ROOT = Get-Location }\n\n# Helper: check if Prisma client exists\nfunction Ensure-PrismaClient {\n    $clientPath = Join-Path $PROJECT_ROOT "backend\node_modules\@prisma\client"\n    if (-Not (Test-Path $clientPath)) {\n        Write-Host "[INFO] Prisma client missing – generating..." -ForegroundColor Yellow\n        Push-Location (Join-Path $PROJECT_ROOT "backend")\n        try { & npx.cmd prisma generate } catch { Write-Host "[WARN] Prisma generate failed, proceeding anyway." -ForegroundColor DarkYellow }\n        Pop-Location\n    } else {\n        Write-Host "[INFO] Prisma client already present – skipping generation." -ForegroundColor Green\n    }\n}\n\n# Ensure Prisma client is ready\nEnsure-PrismaClient\n\n# 1️⃣ Start backend server (detached)\nWrite-Host "[INFO] Launching backend API..." -ForegroundColor Cyan\nPush-Location (Join-Path $PROJECT_ROOT "backend")\n$BackendProcess = Start-Process -FilePath "node" -ArgumentList "api/server.js" -NoNewWindow -PassThru\nPop-Location\n\n# 2️⃣ Build frontend for production\nWrite-Host "[INFO] Building frontend (production)…" -ForegroundColor Cyan\nPush-Location (Join-Path $PROJECT_ROOT "my-project")\n& npm.cmd run build\nPop-Location\n\n# 3️⃣ Serve the built files\nWrite-Host "[INFO] Serving frontend on http://localhost:5173" -ForegroundColor Cyan\nPush-Location (Join-Path $PROJECT_ROOT "my-project\dist")\n# npx serve is a tiny static file server; install globally if missing\nif (-Not (Get-Command serve -ErrorAction SilentlyContinue)) {\n    Write-Host "[WARN] 'serve' not found – installing..." -ForegroundColor Yellow\n    & npm.cmd install -g serve\n}\n$FrontendProcess = Start-Process -FilePath "serve" -ArgumentList "-s . -l 5173" -NoNewWindow -PassThru\nPop-Location\n\nWrite-Host "✅ Demo is running!" -ForegroundColor Green\nWrite-Host "   • Backend: http://localhost:3000" -ForegroundColor Yellow\nWrite-Host "   • Frontend: http://localhost:5173" -ForegroundColor Yellow\nWrite-Host "Press Ctrl+C to stop both servers." -ForegroundColor Magenta\n\n# Keep script alive until user stops it\ntry {\n    while ($true) { Start-Sleep -Seconds 5 }\n} finally {\n    Write-Host "[INFO] Stopping servers…" -ForegroundColor Cyan\n    if ($BackendProcess) { Stop-Process -Id $BackendProcess.Id -Force }\n    if ($FrontendProcess) { Stop-Process -Id $FrontendProcess.Id -Force }\n    Write-Host "[DONE] All processes terminated." -ForegroundColor Green\n}
